function getDuoBadgeStats(sharedGames) {
  const totalGames = sharedGames.length;
  const totalWins = sharedGames.filter(g => gameIsWin(g.p1game)).length;
  let bestStreak = 0, curStreak = 0;
  // chronological order
  const sorted = [...sharedGames].sort((a,b) => new Date(a.p1game.ts) - new Date(b.p1game.ts));
  sorted.forEach(g => {
    if (gameIsWin(g.p1game)) { curStreak++; bestStreak = Math.max(bestStreak, curStreak); }
    else curStreak = 0;
  });
  return { totalGames, totalWins, bestStreak };
}

function getEarnedDuoBadges(sharedGames, chemLevel) {
  const stat = getDuoBadgeStats(sharedGames);
  const data = { ...stat, chemLevel };
  return DUO_BADGE_DEFS.filter(b => b.check(data));
}


const FORCED_EVENT_ID = "double_xp"; // set to null to go back to random weekly rotation

function getWeeklyEvent() {
  const weekNum = Math.floor(Date.now() / WEEK_MS);
  if (FORCED_EVENT_ID) {
    const forced = WEEKLY_EVENTS.find(e => e.id === FORCED_EVENT_ID);
    if (forced) return { ...forced, weekNum };
  }
  // Deterministic seeded pick so every player sees the same event this week.
  let h = weekNum * 2654435761;
  h = (h ^ (h >>> 13)) % 100000;
  const idx = Math.abs(h) % WEEKLY_EVENTS.length;
  return { ...WEEKLY_EVENTS[idx], weekNum };
}
function isEventActive(eventId) {
  return getWeeklyEvent().id === eventId;
}

function weekRangeLabel(start) {
  const end = new Date(start.getTime() + 6 * DAY_MS);
  const fmt = (d) => d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
  return `${fmt(start)} – ${fmt(end)}`;
}
function buildLeagueWeeks() {
  return Array.from({ length: 5 }, (_, i) => {
    const start = new Date(LEAGUE_START.getTime() + i * WEEK_MS);
    return { id: `w${i+1}`, label: `Week ${i+1}`, dateRange: weekRangeLabel(start), start: start.toISOString(), type: "swiss", bestOf: 5, opponent: null, result: null };
  });
}
function buildPlayoffRounds() {
  return ["Round of 16","Quarterfinal","Semifinal","Final"].map((label, i) => {
    const start = new Date(PLAYOFF_START.getTime() + i * WEEK_MS);
    return { id: `po${i+1}`, label, dateRange: weekRangeLabel(start), start: start.toISOString(), type: "playoff", bestOf: 7, opponent: null, result: null };
  });
}
function todayAtMidnight() { const d = new Date(); d.setHours(0,0,0,0); return d; }
function safeDateObj(input, fallback = new Date()) {
  const fallbackDate = fallback instanceof Date ? fallback : new Date(fallback || Date.now());
  const d = input instanceof Date ? input : new Date(input ?? fallbackDate);
  if (Number.isFinite(d.getTime())) return d;
  if (Number.isFinite(fallbackDate.getTime())) return fallbackDate;
  return new Date();
}
function dateKey(d) { return safeDateObj(d).toISOString().slice(0,10); }
function fmtDay(d) { return safeDateObj(d).toLocaleDateString("en-US", { weekday:"short", month:"short", day:"numeric" }); }
function fmtDayShort(d) { return safeDateObj(d).toLocaleDateString("en-US", { weekday:"short" }); }
function fmtRelTime(iso) {
  const diff = Date.now() - safeDateObj(iso).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return "just now";
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs/24)}d ago`;
}
function bbHaptic(pattern = 14) {
  try {
    if (typeof navigator !== "undefined" && typeof navigator.vibrate === "function") navigator.vibrate(pattern);
  } catch (_) {}
}
function tKey(dk, pid) { return `${dk}__${pid}`; }
function normalizeGameMode(mode) {
  const m = String(mode || "").toLowerCase();
  if (m.includes("1v1") || m.includes("duel")) return "1v1";
  if (m.includes("2v2") || m.includes("double")) return "2v2";
  if (m.includes("3v3") || m.includes("standard") || m.includes("trios")) return "3v3";
  return String(mode || "");
}

function gameIsWin(game) {
  if (game?.result) return ["victory", "win", "won"].includes(String(game.result).toLowerCase());
  const our = Number(game?.ourScore);
  const their = Number(game?.theirScore);
  return Number.isFinite(our) && Number.isFinite(their) && our > their;
}
function getDisplayedOurScore(game) {
  const rawOur = Number(game?.ourScore);
  const goals = Number(game?.goals);
  const detectedOur = Number(game?.parseDetectedOurScore);
  // Parse sometimes returns player goals but not final team score, or returns team score as 0.
  // Never let a saved/detected 0 hide a player who actually scored.
  if ((!Number.isFinite(rawOur) || rawOur <= 0) && Number.isFinite(goals) && goals > 0) return goals;
  if (Number.isFinite(rawOur)) return rawOur;
  if (Number.isFinite(detectedOur) && detectedOur > 0) return detectedOur;
  return Number.isFinite(goals) ? goals : 0;
}
function formatGameScore(game) {
  const our = getDisplayedOurScore(game);
  const theirRaw = game?.theirScore;
  const theirKnown = theirRaw !== null && theirRaw !== undefined && theirRaw !== "" && Number.isFinite(Number(theirRaw));
  return `${our} – ${theirKnown ? Number(theirRaw) : "?"}`;
}
function applySyncedTeamScores(importedGames, result) {
  const games = Array.isArray(importedGames) ? importedGames : [];
  const detectedOurScores = games
    .map(g => Number(g?.parseDetectedOurScore))
    .filter(n => Number.isFinite(n));
  const detectedTheirScores = games
    .map(g => Number(g?.parseDetectedTheirScore))
    .filter(n => Number.isFinite(n));
  const rawDetectedOurScore = detectedOurScores.length && detectedOurScores.every(n => n === detectedOurScores[0])
    ? detectedOurScores[0]
    : null;
  const detectedTheirScore = detectedTheirScores.length && detectedTheirScores.every(n => n === detectedTheirScores[0])
    ? detectedTheirScores[0]
    : null;
  const summedGoals = games.reduce((sum, g) => sum + (Number(g?.goals) || 0), 0);
  const detectedOurScore = Number.isFinite(rawDetectedOurScore) && (rawDetectedOurScore > 0 || summedGoals <= 0) ? rawDetectedOurScore : null;
  const fallbackOurScore = Number.isFinite(detectedOurScore) ? detectedOurScore : summedGoals;
  return games.map(g => {
    const ownDetectedRaw = Number(g?.parseDetectedOurScore);
    const ownDetected = Number.isFinite(ownDetectedRaw) && (ownDetectedRaw > 0 || (Number(g?.goals) || 0) <= 0) ? ownDetectedRaw : null;
    const theirDetected = Number(g?.parseDetectedTheirScore);
    const nextOurScore = Number.isFinite(ownDetected) ? ownDetected : fallbackOurScore;
    const nextTheirScore = g.opponentScoreManual
      ? (g.theirScore === null || g.theirScore === undefined || g.theirScore === "" ? null : Number(g.theirScore))
      : Number.isFinite(theirDetected)
        ? theirDetected
        : Number.isFinite(detectedTheirScore)
          ? detectedTheirScore
          : null;
    return {
      ...g,
      ourScore: nextOurScore,
      theirScore: nextTheirScore,
      opponentScoreManual: !!g.opponentScoreManual || Number.isFinite(theirDetected) || Number.isFinite(detectedTheirScore),
      result,
    };
  });
}

function normalizeStatForRender(game, idx = 0) {
  if (!game || typeof game !== "object") return null;
  const rawTs = game.ts || game.date || game.createdAt || game.startedAt || game.matchDate || Date.now();
  const d = safeDateObj(rawTs);
  return {
    ...game,
    id: game.id || game.matchId || game.sessionCode || `restored_game_${idx}_${d.getTime()}`,
    ts: d.toISOString(),
    mode: game.mode || game.playlist || "3v3",
  };
}
function sanitizeStatsForRender(stats) {
  return (Array.isArray(stats) ? stats : []).map(normalizeStatForRender).filter(Boolean);
}


function isMeaningfulStatsSnapshot(v) {
  if (!Array.isArray(v) || v.length === 0) return false;
  return v.some(g => g && typeof g === "object" && (g.playerId || g.id || g.matchId || g.ts || g.date));
}
function statsSnapshotWeight(v) {
  if (!Array.isArray(v)) return 0;
  return v.filter(g => g && typeof g === "object").length;
}
function shouldRejectIncomingStatsSnapshot(incoming, current) {
  if (!Array.isArray(incoming)) return true;
  const currentGood = isMeaningfulStatsSnapshot(current);
  const incomingGood = isMeaningfulStatsSnapshot(incoming);
  if (currentGood && !incomingGood) return true;
  const currentWeight = statsSnapshotWeight(current);
  const incomingWeight = statsSnapshotWeight(incoming);
  return currentGood && currentWeight >= 3 && incomingWeight > 0 && incomingWeight < Math.max(2, Math.floor(currentWeight * 0.35));
}
function backupHasMoreStatsData(backup, current) {
  if (!isMeaningfulStatsSnapshot(backup)) return false;
  return statsSnapshotWeight(backup) > statsSnapshotWeight(current);
}
function isMeaningfulChemistrySnapshot(v) {
  if (!v || typeof v !== "object" || Array.isArray(v)) return false;
  const keys = Object.keys(v).filter(k => !String(k).startsWith("__") && k !== "_resetVersion");
  return keys.some(k => {
    const val = v[k];
    return typeof val === "number" ? val > 0 : !!val;
  });
}
function backupHasMoreChemistryData(backup, current) {
  if (!isMeaningfulChemistrySnapshot(backup)) return false;
  if (!isMeaningfulChemistrySnapshot(current)) return true;
  const b = Object.keys(backup || {}).filter(k => !String(k).startsWith("__") && k !== "_resetVersion").length;
  const c = Object.keys(current || {}).filter(k => !String(k).startsWith("__") && k !== "_resetVersion").length;
  return b > c;
}

function isMeaningfulPointsSnapshot(pts) {
  if (!pts || typeof pts !== "object" || Array.isArray(pts)) return false;
  const keys = Object.keys(pts).filter(k => !String(k).startsWith("__"));
  if (!keys.length) return false;
  const hasPlayerScore = PLAYERS.some(p => Object.prototype.hasOwnProperty.call(pts, p.id));
  const hasInventory = PLAYERS.some(p => Array.isArray(pts[p.id + "_owned"]) && pts[p.id + "_owned"].length > 0);
  const hasEquipped = PLAYERS.some(p => pts[p.id + "_equipped"] && typeof pts[p.id + "_equipped"] === "object");
  return hasPlayerScore || hasInventory || hasEquipped || keys.length > 4;
}

function looksLikeWipedPointsSnapshot(pts) {
  if (!pts || typeof pts !== "object" || Array.isArray(pts)) return false;
  const keys = Object.keys(pts).filter(k => !String(k).startsWith("__"));
  if (!keys.length) return false;
  const hasPlayerScore = PLAYERS.some(p => Object.prototype.hasOwnProperty.call(pts, p.id));
  const hasInventory = PLAYERS.some(p => Array.isArray(pts[p.id + "_owned"]) && pts[p.id + "_owned"].length > 0);
  const hasEquipped = PLAYERS.some(p => pts[p.id + "_equipped"] && typeof pts[p.id + "_equipped"] === "object" && Object.keys(pts[p.id + "_equipped"]).length > 0);
  const safeSystemKey = (k) => (
    /_(bonusSpins|bonusSlots)$/.test(k) ||
    k.includes("test_wheel_spin") ||
    /^weekly_challenge_reset_v/i.test(k) ||
    /weeklyChallengeResetVersion/i.test(k) ||
    /^challenge_/i.test(k) ||
    /live_poll/i.test(k)
  );
  const onlySystemKeys = keys.every(safeSystemKey);
  return !hasPlayerScore && !hasInventory && !hasEquipped && keys.length <= 8 && onlySystemKeys;
}

function shouldRejectIncomingPointsSnapshot(incoming, current) {
  if (!incoming || typeof incoming !== "object" || Array.isArray(incoming)) return true;
  if (looksLikeWipedPointsSnapshot(incoming)) return true;
  const currentMeaningful = isMeaningfulPointsSnapshot(current);
  const incomingMeaningful = isMeaningfulPointsSnapshot(incoming);
  if (currentMeaningful && !incomingMeaningful) return true;
  const incomingKeys = Object.keys(incoming || {}).filter(k => !String(k).startsWith("__")).length;
  const currentKeys = Object.keys(current || {}).filter(k => !String(k).startsWith("__")).length;
  return currentMeaningful && incomingKeys > 0 && incomingKeys < Math.max(3, Math.floor(currentKeys * 0.35));
}

function backupHasMorePointData(backup, current) {
  if (!isMeaningfulPointsSnapshot(backup)) return false;
  if (!current || typeof current !== "object") return true;
  const backupKeys = Object.keys(backup).filter(k => !String(k).startsWith("__")).length;
  const currentKeys = Object.keys(current).filter(k => !String(k).startsWith("__")).length;
  const backupHasScores = PLAYERS.some(p => Object.prototype.hasOwnProperty.call(backup, p.id));
  const currentHasScores = PLAYERS.some(p => Object.prototype.hasOwnProperty.call(current, p.id));
  return backupKeys > currentKeys || (backupHasScores && !currentHasScores);
}

function isMeaningfulGenericSnapshot(v) {
  if (!v || typeof v !== "object" || Array.isArray(v)) return false;
  const keys = Object.keys(v).filter(k => !String(k).startsWith("__"));
  if (!keys.length) return false;
  return keys.some(k => {
    const val = v[k];
    if (Array.isArray(val)) return val.length > 0;
    if (val && typeof val === "object") return Object.keys(val).length > 0;
    return val !== null && val !== undefined && val !== false && val !== 0 && val !== "";
  });
}


function hasAnyStoredKey(v) {
  return !!(v && typeof v === "object" && !Array.isArray(v) && Object.keys(v).filter(k => !String(k).startsWith("__")).length);
}

function isPassXPSnapshot(v) {
  if (!v || typeof v !== "object" || Array.isArray(v)) return false;
  return PLAYERS.some(p => (
    Object.prototype.hasOwnProperty.call(v, p.id) ||
    Object.prototype.hasOwnProperty.call(v, `${p.id}_freeXP`) ||
    Object.prototype.hasOwnProperty.call(v, `${p.id}_premiumXP`)
  ));
}

function isPassPremiumSnapshot(v) {
  if (!v || typeof v !== "object" || Array.isArray(v)) return false;
  return PLAYERS.some(p => Object.prototype.hasOwnProperty.call(v, p.id));
}

function shouldAcceptPassXPUpdate(incoming, current) {
  if (!incoming || typeof incoming !== "object" || Array.isArray(incoming)) return false;
  if (!hasAnyStoredKey(incoming)) return false;
  return true;
}

function shouldAcceptPremiumUpdate(incoming, current) {
  if (!incoming || typeof incoming !== "object" || Array.isArray(incoming)) return false;
  if (!hasAnyStoredKey(incoming)) return false;
  return true;
}

function getFreePassXPForPlayer(passXP, playerId) {
  const direct = Number(passXP?.[`${playerId}_freeXP`]);
  if (Number.isFinite(direct)) return Math.max(0, direct);
  const legacy = Number(passXP?.[playerId]);
  return Number.isFinite(legacy) ? Math.max(0, legacy) : 0;
}

function getPremiumPassXPForPlayer(passXP, playerId, hasPremium) {
  const direct = Number(passXP?.[`${playerId}_premiumXP`]);
  if (Number.isFinite(direct)) return Math.max(0, direct);
  const legacy = Number(passXP?.[playerId]);
  const base = Number.isFinite(legacy) ? Math.max(0, legacy) : 0;
  return hasPremium ? base + (PASS_PREMIUM_HEAD_START * XP_PER_TIER) : 0;
}

function backupHasMoreGenericData(backup, current) {
  if (!isMeaningfulGenericSnapshot(backup)) return false;
  if (!current || typeof current !== "object" || Array.isArray(current)) return true;
  const backupKeys = Object.keys(backup).filter(k => !String(k).startsWith("__"));
  const currentKeys = Object.keys(current).filter(k => !String(k).startsWith("__"));
  if (currentKeys.length === 0) return true;
  if (backupKeys.length > currentKeys.length) return true;
  const backupWeight = backupKeys.reduce((sum, k) => {
    const val = backup[k];
    if (Array.isArray(val)) return sum + val.length + 1;
    if (val && typeof val === "object") return sum + Object.keys(val).length + 1;
    return sum + (val ? 1 : 0);
  }, 0);
  const currentWeight = currentKeys.reduce((sum, k) => {
    const val = current[k];
    if (Array.isArray(val)) return sum + val.length + 1;
    if (val && typeof val === "object") return sum + Object.keys(val).length + 1;
    return sum + (val ? 1 : 0);
  }, 0);
  return backupWeight > currentWeight;
}

// ===================== MMR helpers =====================
const RL_PLAYLISTS = ["Ranked Duel 1v1","Ranked Doubles 2v2","Ranked Standard 3v3"];
function deterministicMMR(seed, idx) {
  let h = 0;
  for (let i = 0; i < seed.length; i++) h = (h * 31 + seed.charCodeAt(i)) >>> 0;
  return 700 + (h % 900) + idx * 60;
}


function rlRankFromTierValue(tierValue) {
  const ranks = [
    "Unranked",
    "Bronze I", "Bronze II", "Bronze III",
    "Silver I", "Silver II", "Silver III",
    "Gold I", "Gold II", "Gold III",
    "Platinum I", "Platinum II", "Platinum III",
    "Diamond I", "Diamond II", "Diamond III",
    "Champion I", "Champion II", "Champion III",
    "Grand Champion I", "Grand Champion II", "Grand Champion III",
    "Supersonic Legend"
  ];

  return ranks[tierValue] || "Unranked";
}

function normalizeRankNameForDisplay(rankName, playlist = "", playerName = "") {
  let rank = String(rankName || "Unranked").trim();
  rank = rank.replace(/\s*[-–—]?\s*(division|div)\s+(i{1,3}|iv)$/i, "").trim();

  // Old saved profiles could say things like "Silver IV" because the app mixed rank tiers with divisions.
  // Rocket League ranks only go I, II, III at the tier level; divisions are separate.
  rank = rank.replace(/\b(Bronze|Silver|Gold|Platinum|Diamond|Champion)\s+IV\b/i, "$1 III");

  // Known repaired value after the wipe/resync issue: apcards5 2v2 is Gold III, not the invalid Silver IV.
  if (playerName === "apcards5" && playlist === "Ranked Doubles 2v2" && /silver\s+iii?/i.test(rank)) {
    rank = "Gold III";
  }
  return rank || "Unranked";
}

function getRankInfoFromSegment(seg, fallback = {}) {
  const tierMeta =
    seg?.stats?.tier?.metadata?.name ||
    seg?.stats?.tier?.displayValue ||
    seg?.stats?.tier?.metadata?.tierName ||
    rlRankFromTierValue(seg?.stats?.tier?.value) ||
    fallback.rank ||
    "Unranked";
  const divisionRaw =
    seg?.stats?.division?.metadata?.name ||
    seg?.stats?.division?.displayValue ||
    seg?.stats?.division?.value ||
    fallback.division ||
    "";
  const division = String(divisionRaw || "")
    .replace(/^division\s*/i, "Div ")
    .replace(/^div\s*/i, "Div ")
    .trim();
  return {
    rank: normalizeRankNameForDisplay(tierMeta, fallback.playlist || "", fallback.playerName || ""),
    division,
  };
}


function getRankImage(rankName) {
  if (!rankName) return null;

  const r = normalizeRankNameForDisplay(rankName).toLowerCase();

  if (r.includes("supersonic")) return "/ranks/Supersonic Legend.png";

  if (r.includes("grand champion iii")) return "/ranks/Grand Champion III.png";
  if (r.includes("grand champion ii")) return "/ranks/Grand Champion II.png";
  if (r.includes("grand champion")) return "/ranks/Grand Champion I.png";

  if (r.includes("champion iii")) return "/ranks/Champion III.png";
  if (r.includes("champion ii")) return "/ranks/Champion II.png";
  if (r.includes("champion")) return "/ranks/Champion I.png";

  if (r.includes("diamond iii")) return "/ranks/Diamond III.png";
  if (r.includes("diamond ii")) return "/ranks/Diamond II.png";
  if (r.includes("diamond")) return "/ranks/Diamond I.png";

  if (r.includes("platinum iii")) return "/ranks/Platinum III.png";
  if (r.includes("platinum ii")) return "/ranks/Platinum II.png";
  if (r.includes("platinum")) return "/ranks/Platinum I.png";

  if (r.includes("gold iii")) return "/ranks/Gold III.png";
  if (r.includes("gold ii")) return "/ranks/Gold II.png";
  if (r.includes("gold")) return "/ranks/Gold I.png";

  if (r.includes("silver iii")) return "/ranks/Silver III.png";
  if (r.includes("silver ii")) return "/ranks/Silver II.png";
  if (r.includes("silver")) return "/ranks/Silver I.png";

  if (r.includes("bronze iii")) return "/ranks/Bronze III.png";
  if (r.includes("bronze ii")) return "/ranks/Bronze II.png";
  if (r.includes("bronze")) return "/ranks/Bronze I.png";

  if (r.includes("unranked")) return "/ranks/Unranked.png";

  return null;
}



function rankFromMMR(mmr) {
  const tiers = [
    { name:"Bronze", max:300 },{ name:"Silver", max:600 },{ name:"Gold", max:900 },
    { name:"Platinum", max:1200 },{ name:"Diamond", max:1500 },{ name:"Champion", max:1800 },
    { name:"Grand Champion", max:2100 },{ name:"Supersonic Legend", max:99999 },
  ];
  const tier = tiers.find((t) => mmr < t.max) || tiers[tiers.length-1];
  const div  = Math.max(1, Math.min(4, Math.ceil(((mmr - (tier.max-300)) / 300) * 4)));
  return `${tier.name}${tier.name === "Supersonic Legend" ? "" : " "+["I","II","III","IV"][div-1]}`;
}



