const PASS_WEEKLY_FIELDS = ["goals", "assists", "saves", "shots"];
const TIME_GOALS_BY_WEEK = [6, 7, 8, 9, 10, 11, 12, 13];

function getWeeklyPassChallenge(playerId, stats) {
  const idx = PLAYERS.findIndex(p => p.id === playerId);
  const weekNum = Math.floor(Date.now() / WEEK_MS); // hours, ramps up each week toward tournament
  const field = PASS_WEEKLY_FIELDS[(weekNum + idx) % PASS_WEEKLY_FIELDS.length];
  const pg = stats.filter(g => g.playerId === playerId && g.mode === "3v3");
  const avg = pg.length ? pg.reduce((s,g) => s+(g[field]||0), 0)/pg.length : 0;
  const target = Math.round((avg + 1) * 10) / 10;
  return { field, target, weekNum };
}
function tierFromXP(xp, cap) {
  const tier = Math.min(cap, Math.floor(xp / XP_PER_TIER));
  const xpIntoTier = xp - tier * XP_PER_TIER;
  return { tier, xpIntoTier, xpForNext: XP_PER_TIER };
}
const DOUBLE_XP_DURATION_MS = 24 * 60 * 60 * 1000; // 24 hours
function getActiveBoostMultiplier(playerId, activeBoosts) {
  const boost = activeBoosts?.[playerId];
  if (!boost) return 1;
  if (boost.type !== "double_xp") return 1;
  if (Date.now() > new Date(boost.expiresAt).getTime()) return 1;
  return 2;
}
function isOnline(ts) {
  if (!ts) return false;
  return Date.now() - new Date(ts).getTime() < 45000;
}

function PlayerNameDisplay({ playerId, points }) {
  const player = PLAYERS.find(p => p.id === playerId);
  if (!player) return null;
  const owned = (points?.[playerId + "_owned"]) || [];
  const equipped = points?.[playerId + "_equipped"] || {};
function getPassRewardValue(ownedId) {
  const parts = ownedId.split("_");
  const t = parts[1]; const tier = Number(parts[2]);
  const rewards = t === "free" ? FREE_PASS_REWARDS : PREMIUM_PASS_REWARDS;
  return rewards[tier] || null;
}
const colorItem = owned.find(id => {
  if (equipped[id]) {
    const shop = getAllShopItems().find(i => i.id === id && i.type === "color");
    if (shop) return true;
    if (id.startsWith("pass_")) { const r = getPassRewardValue(id); return r?.type === "color"; }
  }
  return false;
});
const iconItem = owned.find(id => {
  if (equipped[id]) {
    const shop = getAllShopItems().find(i => i.id === id && i.type === "icon");
    if (shop) return true;
    if (id.startsWith("pass_")) { const r = getPassRewardValue(id); return r?.type === "icon"; }
  }
  return false;
});
const titleItem = owned.find(id => {
  if (equipped[id]) {
    const shop = getAllShopItems().find(i => i.id === id && i.type === "title");
    if (shop) return true;
    if (id.startsWith("pass_")) { const r = getPassRewardValue(id); return r?.type === "title"; }
  }
  return false;
});
const color = colorItem ? (getAllShopItems().find(i => i.id === colorItem)?.value || (colorItem.startsWith("pass_") ? getPassRewardValue(colorItem)?.value : null) || player.color) : player.color;
const icon = iconItem ? (getAllShopItems().find(i => i.id === iconItem)?.value || (iconItem.startsWith("pass_") ? getPassRewardValue(iconItem)?.value : null)) : null;
const title = titleItem ? (getAllShopItems().find(i => i.id === titleItem)?.value || (titleItem.startsWith("pass_") ? getPassRewardValue(titleItem)?.value : null)) : null;
  return (
    <div style={{display:"flex",flexDirection:"column",gap:1}}>
      <span style={{ color, fontWeight: 700 }}>{icon && <span style={{ marginRight: 4 }}>{icon}</span>}{player.name}</span>
{title && <span style={{fontSize:9.5,color:"#8B92A8",fontWeight:600,letterSpacing:0.5}}>{title}</span>}
    </div>
  );
}





function getEquippedShopItemByType(points, playerId, type) {
  const owned = Array.isArray(points?.[playerId + "_owned"]) ? points[playerId + "_owned"] : [];
  const equipped = points?.[playerId + "_equipped"] || {};
  return owned.map(id => getAllShopItems().find(i => i.id === id)).find(item => item?.type === type && equipped[item.id]) || null;
}

function getPresenceBorderVisualStyle(points, playerId, online = false) {
  const item = getEquippedShopItemByType(points, playerId, "border");
  if (!item) return { border:`1px solid ${online?"rgba(124,255,178,0.15)":"rgba(255,255,255,0.05)"}` };
  if (item?.custom && item.borderColor) {
    return { border:`1px solid ${item.borderColor}`, boxShadow:`0 0 0 1px ${item.borderColor}22, 0 0 24px ${item.borderGlow || item.borderColor}26` };
  }
  const map = {
    lime:   { border:"1px solid rgba(184,255,77,0.62)", boxShadow:"0 0 0 1px rgba(184,255,77,0.12), 0 0 22px rgba(184,255,77,0.13)" },
    gold:   { border:"1px solid rgba(255,209,102,0.70)", boxShadow:"0 0 0 1px rgba(255,209,102,0.15), 0 0 24px rgba(255,209,102,0.12)" },
    violet: { border:"1px solid rgba(167,139,250,0.68)", boxShadow:"0 0 0 1px rgba(167,139,250,0.14), 0 0 24px rgba(167,139,250,0.12)" },
    ice:    { border:"1px solid rgba(77,158,255,0.70)", boxShadow:"0 0 0 1px rgba(77,158,255,0.15), 0 0 24px rgba(77,158,255,0.13)" },
    danger: { border:"1px solid rgba(255,92,138,0.72)", boxShadow:"0 0 0 1px rgba(255,92,138,0.14), 0 0 24px rgba(255,92,138,0.13)" },
    matrix: { border:"1px solid rgba(184,255,77,0.70)", boxShadow:"0 0 0 1px rgba(184,255,77,0.14), 0 0 24px rgba(184,255,77,0.14)" },
    sunset: { border:"1px solid rgba(255,140,50,0.72)", boxShadow:"0 0 0 1px rgba(255,97,193,0.14), 0 0 24px rgba(255,140,50,0.13)" },
    slime: { border:"1px solid rgba(109,255,138,0.72)", boxShadow:"0 0 0 1px rgba(109,255,138,0.14), 0 0 24px rgba(109,255,138,0.13)" },
    void: { border:"1px solid rgba(126,184,255,0.42)", boxShadow:"0 0 0 1px rgba(126,184,255,0.10), 0 0 26px rgba(0,0,0,0.38)" },
    arcade: { border:"1px solid rgba(255,97,193,0.72)", boxShadow:"0 0 0 1px rgba(77,158,255,0.14), 0 0 24px rgba(255,97,193,0.13)" },
  };
  return map[item.value] || map.lime;
}

